# scripts/run_prompt_eval.py
import argparse, yaml, json, sys
from app.prompts import load_prompt

def run_eval(prompt_dir: str, suite_path: str, min_pass_rate: float) -> None:
    parts = prompt_dir.strip("/").split("/")   # e.g. ['prompts', 'rag-answer', 'v2']
    feature, version = parts[-2], parts[-1]
    prompt = load_prompt(feature, version)

    with open(suite_path) as f:
        suite = yaml.safe_load(f)

    passed = 0
    for case in suite["cases"]:
        response = call_model(prompt, **case["inputs"])
        result = evaluate(response, case["expected"], case.get("criteria", []))
        if result["passed"]:
            passed += 1
        else:
            print(f"FAIL [{case['id']}]: {result['reason']}")

    pass_rate = passed / len(suite["cases"])
    print(f"\nPass rate: {pass_rate:.0%} ({passed}/{len(suite['cases'])})")
    print(f"Prompt SHA: {prompt.sha256[:12]}")

    if pass_rate < min_pass_rate:
        print(f"GATE FAIL: {pass_rate:.0%} < {min_pass_rate:.0%} required")
        sys.exit(1)
    print("GATE PASS")

def call_model(prompt, **inputs):
    import openai
    client = openai.OpenAI()
    resp = client.chat.completions.create(
        model=prompt.config["model"],
        temperature=prompt.config["temperature"],
        max_tokens=prompt.config["max_tokens"],
        messages=[
            {"role": "system", "content": prompt.system},
            {"role": "user", "content": prompt.render_user(**inputs)},
        ],
    )
    return resp.choices[0].message.content

def evaluate(response: str, expected: dict, criteria: list[str]) -> dict:
    if "contains" in expected:
        for phrase in expected["contains"]:
            if phrase.lower() not in response.lower():
                return {"passed": False, "reason": f"missing: '{phrase}'"}
    if "not_contains" in expected:
        for phrase in expected["not_contains"]:
            if phrase.lower() in response.lower():
                return {"passed": False, "reason": f"forbidden phrase: '{phrase}'"}
    return {"passed": True, "reason": ""}

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--prompt-dir"); parser.add_argument("--suite")
    parser.add_argument("--min-pass-rate", type=float, default=0.9)
    args = parser.parse_args()
    run_eval(args.prompt_dir, args.suite, args.min_pass_rate)
